const PROVISION_INDEX = [{"id": "s1-1", "section": "§1.1", "name": "Individual Sovereignty Floor", "text": "Every person holds an individual sovereignty that government authority may limit only as this Constitution permits — and may never eliminate. No official, institution, or emergency suspends this floor."}, {"id": "s1-2", "section": "§1.2", "name": "Prohibition of Torture and Cruel Treatment", "text": "Absolute prohibition on torture, cruel treatment, and degrading punishment. No exception exists — not for national security, not for emergency, not for military operations. One of six permanently unamendable provisions under §15.3.a."}, {"id": "s1-3", "section": "§1.3", "name": "Prohibition of Slavery and Forced Labor", "text": "Slavery, forced labor, and involuntary servitude are prohibited in all forms. The only carve-out is jury service as defined in §10.6.a. Also permanently unamendable ."}, {"id": "s1-8", "section": "§1.8", "name": "Equality and Non-Discrimination", "text": "Every person is equal before the law. No person may be discriminated against on the basis of the enumerated characteristics. Distinctions based on race, ethnicity, religion, sex, sexual orientation, gender identity, national origin, or disability are presumptively unconstitutional, requiring a compe"}, {"id": "s1-9-a", "section": "§1.9.a", "name": "Physical Sovereignty", "text": "Every person has the absolute right to refuse any medical procedure or biological sampling. No mandate is permissible under any declared emergency under any declared emergency unless the individual provides uncoerced, revocable written consent."}, {"id": "s1-4-a", "section": "§1.4.a", "name": "Censorship by Proxy", "text": "No government agent may coerce, incentivize, or direct private entities to suppress protected speech."}, {"id": "s1-4-b", "section": "§1.4.b", "name": "Separation of Church and State", "text": "No religion may be established by law, and public funds directed to religious organizations must comply with the equality requirements of §1.8. The separation of church and state is structural, not merely preferential."}, {"id": "s1-9-b", "section": "§1.9.b", "name": "Data Ownership", "text": "Individuals own their personal data, likeness, and biometric information , likeness, and biometric information. Data collected by any government actor is subject to strict necessity limits — it may not be retained beyond the purpose for which it was collected, shared with third parties without..."}, {"id": "s1-9-c", "section": "§1.9.c", "name": "Encryption Protection", "text": "Cryptographic keys are private property. No court or agency may compel their disclosure. Absolute rule, consistent with §1.16's self-incrimination prohibition — closes the digital search-and-seizure loophole present in most existing constitutions."}, {"id": "s1-10-a", "section": "§1.10.a", "name": "Home and Digital Privacy", "text": "'Home' extends to all physical residences and all digital spaces secured by private cryptographic keys. Access requires a warrant specifying the precise data target or physical space, verified on the NRS before execution . General warrants — broad or unspecified authorizations — are absolutely prohi"}, {"id": "s1-10-b", "section": "§1.10.b", "name": "Eminent Domain", "text": "Seizure of private property requires proof of absolute public necessity, payment of 150% of fair market value, and NRS publication. Private-to-private transfer via eminent domain via eminent domain — using government condemnation to benefit another private party — is constitutionally prohibited."}, {"id": "s1-11-a", "section": "§1.11.a", "name": "Right to Bear Arms", "text": "The right to keep and bear arms for personal defense and hunting must not be infringed . The provision is deliberately narrow in scope — personal defense and hunting — which bounds the right without eliminating it."}, {"id": "s1-11-b", "section": "§1.11.b", "name": "State Licensing Latitude", "text": "States may establish licensing and safety training requirements as a condition of carrying or possessing firearms. States may regulate the exercise of the right but may not use regulation as a prohibition by another name."}, {"id": "s1-11-c", "section": "§1.11.c", "name": "Non-Prohibition Principle", "text": "No State requirement may function as an effective prohibition on keeping or bearing arms. A requirement is an effective prohibition if it imposes costs, delays, or conditions that make lawful ownership practically inaccessible to ordinary citizens. The burden of proof lies with the State to demonstr"}, {"id": "s1-13-a", "section": "§1.13.a", "name": "First Appearance", "text": "Any person taken into custody must appear before a judicial officer within 72 hours Measured from the moment of physical custody, not from formal arrest. Clock does not pause for weekends or public holidays. of arrest. At the First Appearance, the judge must determine whether custody is lawful and w"}, {"id": "s1-13-b", "section": "§1.13.b", "name": "Habeas Corpus Response Deadline", "text": "A court receiving a habeas corpus petition must rule within 48 hours of filing. No procedural rule may extend this deadline. A court that fails to rule within 48 hours is deemed to have found the detention unlawful is deemed to have found the detention unlawful — the detained person must be released"}, {"id": "s1-13-c", "section": "§1.13.c", "name": "Habeas Corpus", "text": "Any person detained by the State has the absolute right to challenge the lawfulness of their confinement before a judge at any time. The right cannot be suspended by emergency declaration by emergency declaration — it appears in §1.25.b's list of absolutely non-derogable rights."}, {"id": "s1-14-a", "section": "§1.14.a", "name": "Right to Counsel", "text": "Any person accused of a crime or subject to detention has the right to retain and consult with a lawyer before questioning. If they cannot afford counsel, the Republic provides it. The right attaches from the moment of accusation or detention , not from formal charging."}, {"id": "s1-14-b", "section": "§1.14.b", "name": "Caseload Guarantee", "text": "the Legislature must establish maximum caseload limits for publicly funded defense — ensuring that the right to counsel means genuine preparation, not nominal presence. Public defenders must be resourced equivalently to prosecutorial offices handling comparable cases."}, {"id": "s1-14-c", "section": "§1.14.c", "name": "Right to Be Informed of Charges", "text": "Any person detained or accused must be informed promptly, in plain language they understand, of the specific grounds for their detention and the charges being considered. Detention without meaningful explanation of its basis is unconstitutional from its first moment."}, {"id": "s1-14-d", "section": "§1.14.d", "name": "Right to Full Disclosure", "text": "Any accused person has the right to full disclosure of all State evidence — including evidence the prosecution does not intend to use — before trial. Any withholding of exculpatory evidence is a constitutional violation, not a procedural irregularity."}, {"id": "s1-15-a", "section": "§1.15.a", "name": "Speedy Trial Principle", "text": "Every accused person has the right to trial without unreasonable delay. Delay caused by the State is not a neutral fact — prolonged pre-trial detention is itself a punishment imposed without verdict. What constitutes unreasonable delay is defined by the Legislature in statute, subject to judicial re"}, {"id": "s1-15-b", "section": "§1.15.b", "name": "Bail Proportionality", "text": "Pre-trial detention may only be ordered where the court makes a specific, individualized finding that the accused poses a genuine flight risk or documented danger to an identifiable person. Financial inability to post bail does not justify detention — bail conditions must be proportionate to what th"}, {"id": "s1-15-c", "section": "§1.15.c", "name": "Protection from Trial Penalties", "text": "The right to trial may not be penalized. A defendant who exercises their right to trial may not receive a harsher sentence than they would have received by entering a guilty plea for the same offense. Sentencing 'trial penalties' are constitutionally prohibited ."}, {"id": "s1-15-d", "section": "§1.15.d", "name": "Source Code Right", "text": "Any accused person has the right to inspect, challenge, and rebut any algorithm, automated system, statistical model, or raw dataset used as evidence or to generate a score influencing their case. Technology-opaque evidence against which no defense can be mounted is constitutionally inadmissible."}, {"id": "s1-16", "section": "§1.16", "name": "Right to Silence", "text": "No person may be compelled to testify against themselves or to produce self-incriminating evidence. The right of silence is complete — silence may not be commented upon or used to draw adverse inferences or used to draw adverse inferences. Consistent with §1.9.c, this extends to cryptographic keys."}, {"id": "s1-17", "section": "§1.17", "name": "Right to a Public Trial", "text": "Every accused person has the right to a public trial before a judge and, in criminal matters, a jury of peers. Secret or closed proceedings are constitutionally prohibited except for the minimal portion where a specific witness's safety requires it — and even then the verdict must be public . Also p"}, {"id": "s1-18-a", "section": "§1.18.a", "name": "No Retroactive Criminal Laws", "text": "No person may be convicted of an act that was not defined as a criminal offense at the time it was committed. No sentence may exceed the maximum available at the time of the offense. The prohibition on retroactive criminal law is absolute and permanently unamendable ."}, {"id": "s1-18-b", "section": "§1.18.b", "name": "Double Jeopardy", "text": "No person may be tried or punished more than once for the same offense arising from the same factual events. Acquittal is final. This applies across all levels of the Republic's court system — a State court acquittal cannot be retried in a federal court on the same facts."}, {"id": "s1-19", "section": "§1.19", "name": "Right to Democratic Participation", "text": "No government action may make voting materially more difficult for any eligible citizen. The right to stand for election is constitutionally coextensive with the right to vote ."}, {"id": "s1-20", "section": "§1.20", "name": "Right to Marry and Found a Family", "text": "The right to marry or form a legally recognized partnership belongs to any two consenting adults regardless of sex, gender, or sexual orientation. The Republic must recognize such partnerships for all legal purposes . The Legislature and States may not create hierarchies of partnership recognition b"}, {"id": "s1-21", "section": "§1.21", "name": "Rights of Children", "text": "Every child has the right to protection from exploitation, abuse, and neglect. In all State actions affecting minors, the welfare and best interests of the child are the primary consideration — not merely one factor to be weighed. The protection of children is the one area where the Individual Sover"}, {"id": "s1-22", "section": "§1.22", "name": "Environmental Accountability", "text": "Article I's environmental provisions establish two constitutional obligations: Government Non-Harm (§1.22.a) prevents authorities from knowingly exposing communities to environmental hazards without disclosure, consultation, and mitigation; Environmental Stewardship (§1.22.b) creates an enforceable "}, {"id": "s1-22-a", "section": "§1.22.a", "name": "Government Non-Harm", "text": "No government authority may knowingly expose any community of Inhabitants to environmental hazards without full disclosure, meaningful consultation, and proportionate mitigation. The Government Non-Harm principle makes environmental poisoning of communities a a constitutional violation, not merely a"}, {"id": "s1-22-b", "section": "§1.22.b", "name": "Environmental Stewardship", "text": "The long-term stewardship of the Republic's natural environment is a constitutional obligation of the federal government — not aspirational language. It creates an enforceable duty to maintain ecological integrity that the Inspectorates are mandated to report on annually."}, {"id": "s1-23", "section": "§1.23", "name": "Federal Education Assistance", "text": "Three interlocking education provisions: §1.23.a requires the Republic to fund education assistance so no child's opportunity depends on their territory's wealth. §1.23.b requires public education to equip students to meet the Constitutional Logic Test standard — education for citizenship is a const"}, {"id": "s1-23-a", "section": "§1.23.a", "name": "Federal Education Assistance", "text": "The Republic must provide adequate education assistance to States and Territories so that no child's educational opportunity is determined primarily by the wealth of their territory. Federal assistance must address the gap between what a jurisdiction can fund locally and what the constitutional lite"}, {"id": "s1-23-b", "section": "§1.23.b", "name": "Constitutional Literacy", "text": "The Republic's constitutional literacy standard for citizenship purposes is the CLT, defined in §5.4. Public education must equip students to meet that standard — education for citizenship is a constitutional obligation, not a civic nicety."}, {"id": "s1-23-c", "section": "§1.23.c", "name": "Parental Right", "text": "Parents retain the right to educate children through alternative means — homeschooling, faith-based schools, alternative institutions — provided those alternatives meet the constitutional literacy standard. The Republic may set the floor; it may not mandate the method."}, {"id": "s1-24", "section": "§1.24", "name": "Housing Non-Exclusion", "text": "Article I's housing provisions create constitutional barriers to exclusion and a constitutional obligation to provide. The Non-Exclusion Principle (§1.24.a) prohibits exclusionary zoning and any regulatory mechanism designed to keep certain populations out. The BNF Housing Obligation (§1.24.b) ancho"}, {"id": "s1-24-a", "section": "§1.24.a", "name": "Non-Exclusion Principle", "text": "No government authority — federal, State, or local — may use regulatory or land-use powers to exclude any person from access to housing on the basis of any characteristic enumerated in §1.8. Exclusionary zoning designed to keep certain populations out of a community is constitutionally prohibited."}, {"id": "s1-24-b", "section": "§1.24.b", "name": "BNF Housing Obligation", "text": "The Republic's obligation to ensure housing access for persons who cannot independently secure it is part of the Basic Needs Floor under §10.1. This provision anchors housing as a BNF category and makes housing exclusion an enforceable constitutional violation."}, {"id": "s1-25-a", "section": "§1.25.a", "name": "Emergency Derogation — Declaration Requirements", "text": "The Republic may temporarily limit rights in this Article through a Declaration issued jointly by the President and Prime Minister stating the specific emergency."}, {"id": "s1-25-b", "section": "§1.25.b", "name": "Non-Derogable Rights", "text": "These five rights are absolute under any circumstances : the prohibition on torture (§1.2); slavery (§1.3); habeas corpus (§1.13); the right to a public trial (§1.17); and no retroactive punishment (§1.18)."}, {"id": "s1-25-c", "section": "§1.25.c", "name": "Inspectorate Continuity", "text": "The three Inspectorates continue to operate with full constitutional authority throughout any emergency — they cannot be suspended or have their mandate reduced by emergency declaration. Accountability infrastructure is precisely most important when emergency powers are active."}, {"id": "s1-25-d", "section": "§1.25.d", "name": "Automatic Expiry and Judicial Review", "text": "Emergency measures lapse automatically at the expiry of the Declaration. Judicial review of any emergency measure is available to any citizen at any time, and courts may rule during the emergency that a specific measure is unconstitutional."}, {"id": "s1-25-e", "section": "§1.25.e", "name": "No Permanent Emergency", "text": "No emergency measure may be made permanent by legislative act . Every emergency measure lapses automatically at the expiry of the Declaration unless re-enacted through the ordinary legislative process. The Legislature may not extend an emergency measure by re-declaration within 60 days of its expiry"}, {"id": "s1-26", "section": "§1.26", "name": "Associated Community Residents", "text": ""}, {"id": "s1-27", "section": "§1.27", "name": "Non-Refoulement", "text": "Absolute prohibition on returning any person to persecution, torture, or death based on the specified grounds. Extends to territorial waters and wherever Republic authorities exercise effective custody . Unamendable."}, {"id": "s2-1", "section": "§2.1", "name": "The President — Term and Transfer", "text": "The President serves a single non-renewable six-year term . No action by the outgoing President is required — transfer of executive authority is automatic at the constitutionally fixed moment."}, {"id": "s2-1-a", "section": "§2.1.a", "name": "Tier 1 — Immediate Defensive Response", "text": "Tier 1 covers immediate response to active, imminent, or ongoing attacks. The President must notify the Legislature within must notify the Legislature within 6 hours ; the Senate Armed Services Committee must authorize within 72 hours for the operation to continue beyond immediate necessity. All Tie"}, {"id": "s2-1-ac", "section": "§2.1.a–c", "name": "Military Authority — Three Tiers", "text": "Presidential military authority is divided into three tiers. Tier 1 is routine; Tier 2 requires parliamentary notification; Tier 3 requires a full parliamentary Declaration of Defense."}, {"id": "s2-1-b", "section": "§2.1.b", "name": "Tier 2 — Senate Armed Services Authorization", "text": "Offensive military operations or defensive deployments transitioning beyond immediate necessity require Senate Armed Services Committee authorization — Tier 2. The SASC must vote within 72 hours of notification. This democratic pause before offensive action is a deliberate design choice."}, {"id": "s2-1-c", "section": "§2.1.c", "name": "Tier 3 — Legislative Declaration of Defense", "text": "All military operations beyond 30 days require a Legislative Declaration of Defense — a 2/3 concurrent majority of both chambers. Once 30 days pass, the Legislature must affirmatively authorize continuation. No executive can use Tier 1 or Tier 2 authority to avoid Tier 3 by claiming continuity of an"}, {"id": "s2-1-e", "section": "§2.1.e", "name": "Privacy Firewall", "text": "Any order for domestic surveillance or intelligence activity directed at Republic citizens requires a judicial warrant. The Privacy Firewall separates national security authority from domestic intelligence operations — the President may not direct surveillance of domestic targets without independent"}, {"id": "s2-1-f", "section": "§2.1.f", "name": "Presidential Veto — Scope", "text": "The President may veto bills that raise a genuine constitutional concern within the presidential domain of defense and diplomacy. A veto is not a general legislative override — it must be grounded in a specific articulable constitutional justification, not policy disagreement. A void veto is simply "}, {"id": "s2-1-f-i", "section": "§2.1.f.i", "name": "Judicial Review and Override", "text": "The Supreme Court reviews any veto challenge within 48 hours. A void veto permits the bill to proceed to enactment. A veto found to be in bad faith — issued as obstruction rather than genuine constitutional concern — may constitute a Rule Violation under §2.7."}, {"id": "s2-1-g", "section": "§2.1.g", "name": "Presidential Clemency", "text": "The President may grant clemency for individuals convicted of offenses within the presidential domain. The Executive Inspectorate must publish a factual background report before any clemency is granted, making the basis permanently public. No self-clemency; no clemency for Rule Violations."}, {"id": "s2-2", "section": "§2.2", "name": "The Prime Minister — Domestic Executive Domain", "text": "The PM is the domestic executive — responsible for all internal governance. Neither executive may direct, countermand, or assume the functions of the other's domain ."}, {"id": "s2-2-a", "section": "§2.2.a", "name": "The Record System Mandate", "text": "The PM must record all executive orders, contracts, and expenditures on the NRS within defined timeframes. Failure to record is itself a constitutional violation — makes the NRS mandate self-enforcing through the Rule Violation mechanism through the Rule Violation mechanism."}, {"id": "s2-2-b", "section": "§2.2.b", "name": "Duty of Refusal", "text": "Civil servants must refuse and report any order that lacks PM fund certification or would require unlawful action. The duty of refusal gives civil servants a constitutional shield — they cannot be disciplined for refusing an unlawful order, and the refusal is itself constitutionally protected action"}, {"id": "s2-2-c", "section": "§2.2.c", "name": "PM Maximum Consecutive Service", "text": "No person may serve as Prime Minister for more than 8 consecutive years. On the date a PM takes office, the Executive Inspectorate records the expiry date on the National Record System."}, {"id": "s2-2-d", "section": "§2.2.d", "name": "Civil Service Integrity", "text": "The PM has constitutional responsibility for civil service integrity — merit-based appointment, politically neutral service, and protection for civil servants who refuse unlawful orders. Using hiring, firing, or assignment to reward or punish political loyalty is a Rule Violation."}, {"id": "s2-2-e", "section": "§2.2.e", "name": "Domestic Emergency Authority", "text": "The PM may declare a domestic state of emergency in response to natural disaster, industrial accident, or public health crisis — not political crisis. The Legislature must ratify within 30 days; the declaration lapses at 30 days without ratification. The 60-day re-declaration bar prevents continuous"}, {"id": "s2-2-g", "section": "§2.2.g", "name": "Ministerial Appointments", "text": "The PM appoints and removes ministers within the Domestic Affairs Council. All ministerial appointments and removals are published to the NRS within 24 hours. Ministers exercise only authority delegated within the PM's constitutional domain — no minister may act outside that domain regardless of how"}, {"id": "s2-3-a", "section": "§2.3.a", "name": "Selection", "text": "The House selects the PM by absolute majority — a majority of all seated members, not just those present. A PM who cannot command a genuine working majority cannot be appointed, preventing minority government through strategic abstention."}, {"id": "s2-3-b", "section": "§2.3.b", "name": "Constructive Vote of No Confidence", "text": "The House may remove the PM through a constructive vote of no confidence — a vote that simultaneously designates a successor. Government continues without gap or dissolution."}, {"id": "s2-3-c", "section": "§2.3.c", "name": "Caretaker Protocol", "text": ""}, {"id": "s2-3-d", "section": "§2.3.d", "name": "Post-Dissolution Election Bar", "text": "Any party or organized faction that held a majority of House seats when dissolution triggered cannot field candidates in the emergency election that follows. The party may return at the next regular election cycle. This prevents the dissolution from simply restoring the conditions that caused it — a"}, {"id": "s2-4-a", "section": "§2.4.a", "name": "Suspensive Veto", "text": "The PM may return any bill to the House with a written Statement of Domestic Concern — a suspensive veto that forces reconsideration but cannot permanently block. The House may re-pass the bill by simple majority after considering the PM's objections. The PM's veto is deliberative, not decisive."}, {"id": "s2-4-ab", "section": "§2.4.a–b", "name": "Suspensive Veto and Fiscal Objection", "text": "The Prime Minister may return any bill to the House with a written Statement of Objection specifying the grounds — constitutional, fiscal, operational, or policy. The Statement is recorded permanently on the National Record System."}, {"id": "s2-6", "section": "§2.6", "name": "Presidential Succession", "text": "If the President dies, is permanently incapacitated, resigns, or is removed, the constitutional succession line is: Senate Speaker → Senate Deputy Speaker → most senior Armed Services Committee member. The PM is deliberately not in the presidential succession line — preventing the domestic executive"}, {"id": "s2-6-b", "section": "§2.6.b", "name": "Incapacity Certification", "text": "The PM has a potential political interest in certifying presidential incapacity. This provision acknowledges the conflict and requires the PM to recuse from incapacity certification where a conflict exists, with the process moving to the Supreme Court."}, {"id": "s2-6-c", "section": "§2.6.c", "name": "Succession-Based Presidential Term", "text": "A succession-based President must stand for election at the next regular National Election Day or in a special election called within 90 days. Succession is an emergency holding mechanism, not a full term grant — democratic authorization must follow."}, {"id": "s2-7", "section": "§2.7", "name": "Constitutional Violations and Rule Violations", "text": "A Rule Violation is a Supreme Court finding that an official has violated a specific constitutional provision. Consequences are automatic — not subject to the official's agreement or the Legislature's confirmation. The framework distinguishes minor violations (triggering the corrective order track u"}, {"id": "s2-7-c", "section": "§2.7.c", "name": "Minor Violations — Corrective Order Track", "text": "A violation is minor — triggering the corrective order track — when it is procedural, involves no evidence of deliberate circumvention, and rights were not materially prejudiced. Good-faith officials who made constitutional errors may correct them without losing office."}, {"id": "s2-7-e", "section": "§2.7.e", "name": "Rule Violations — Legislative Members", "text": "When a Rule Violation finding is issued against a sitting legislator, the automatic consequences are modified: suspended from voting and committee participation (not removed from office); access to classified information revoked; finding automatically referred to the relevant chamber's ethics commit"}, {"id": "s2-8", "section": "§2.8", "name": "Emergency Governance Protocol", "text": "The Emergency Governance Protocol addresses simultaneous loss of both executives and other catastrophic continuity scenarios where the normal succession mechanisms under §2.6 cannot function. It is the constitutional backstop for the Republic's most extreme continuity scenarios — covering attack on "}, {"id": "s2-9-c", "section": "§2.9.c", "name": "Self-Clemency Absolute Prohibition", "text": "No elected or appointed official of the Republic may grant clemency to themselves, to a co-defendant in any matter involving their own conduct, or to any person whose conviction arose from their own acts while in office. Self-clemency is absolutely prohibited ."}, {"id": "s2-10", "section": "§2.10", "name": "Presidential Removal — Two Political Tracks", "text": "Two political removal paths independent of the §2.7 Rule Violation track. These address situations where the President has not committed a technical constitutional violation but has lost democratic confidence. Both require either cross-institutional consensus or direct citizen participation."}, {"id": "s2-10-a", "section": "§2.10.a", "name": "Legislative Removal", "text": "2/3 of full House membership to initiate — a Statement of Grounds specifying the basis for removal accompanies the vote and defines the subject of the Senate trial. 2/3 of full Senate membership to convict and remove. Both thresholds are of full membership, not those present. Trial proceeds under §3"}, {"id": "s2-10-b", "section": "§2.10.b", "name": "Senate Referral to Popular Recall", "text": "Simple majority of full Senate membership may refer the question of presidential removal to a national recall referendum. Removal requires a majority of all eligible voters — not merely those who turn out. One referral per presidential term. The Senate Speaker assumes the presidential succession rol"}, {"id": "s3-1-a", "section": "§3.1.a", "name": "House Membership Floor", "text": "The House has a constitutionally guaranteed minimum membership floor below which no statute may reduce representation."}, {"id": "s3-1-b", "section": "§3.1.b", "name": "Census Authority", "text": "The Legislative Inspectorate — not the Executive — conducts the census for House seat allocation. This prevents the executive branch from influencing seat allocation by controlling the population count."}, {"id": "s3-1-c", "section": "§3.1.c", "name": "Single-Subject Rule", "text": "Every bill must address a single, clearly defined subject identified in its title . Where a bill contains a non-conforming provision, any citizen or legislative minority of one-third may petition the Supreme Court during the Legislative Review Period. The Court severs the non-conforming provision; t"}, {"id": "s3-1-d", "section": "§3.1.d", "name": "Bill Exposure", "text": "Every bill must be published in full on the NRS for a minimum public exposure period before it may be voted on. Secret legislation — drafted and passed the same day — is constitutionally prohibited. Every piece of legislation is publicly reviewable before it becomes law."}, {"id": "s3-3-a", "section": "§3.3.a", "name": "Legislative Mandate Enforcement", "text": "If the Legislature fails to enact a constitutionally mandated statute within the specified timeframe — or within two budget cycles where no timeframe is specified — the matter automatically becomes eligible for an Optional Referendum under §11.1 without requiring..."}, {"id": "s3-3-d", "section": "§3.3.d", "name": "Record System Entry", "text": "The presiding officer of each chamber certifies and records each enacted law on the NRS with a timestamp. Discrepancies between the certified NRS record and any other document resolve in favor of the NRS. The record is what is law."}, {"id": "s3-5", "section": "§3.5", "name": "Impeachment", "text": "This track applies to executive and judicial officers only — legislators are governed by §3.6. Inquiry: 1/3 House minority. Articles: simple majority of full House membership. Senate trial and conviction: 2/3 of full Senate membership . Separate from the §2.10 presidential removal track (which requi"}, {"id": "s3-5-a", "section": "§3.5.a", "name": "Impeachment Inquiry", "text": "Any 1/3 minority of the House may open a formal impeachment inquiry — a deliberately low threshold ensuring opposition parties can trigger accountability proceedings without majority cooperation. The inquiry opens investigation; Articles of Impeachment require a full House simple majority."}, {"id": "s3-5-b", "section": "§3.5.b", "name": "Articles of Impeachment", "text": "The full House votes on Articles of Impeachment by simple majority of the full membership — not those present. Impeachment requires genuine majority support, not the ability to time a vote when opponents are absent."}, {"id": "s3-6-c", "section": "§3.6.c", "name": "Anti-Weaponization Threshold", "text": "Any expulsion vote taking effect within 30 days of a scheduled vote on a bill the expelled member was known to oppose is presumptively retaliatory. This prevents parliamentary majorities from using expulsion to silence dissent before critical votes."}, {"id": "s3-6-d", "section": "§3.6.d", "name": "Consequences and Restoration", "text": ""}, {"id": "s3-6-e", "section": "§3.6.e", "name": "Recall — States and Territories", "text": "States and Territories may establish recall mechanisms for both their Senators and House members by their own statute. State recall and chamber expulsion operate independently — whichever takes effect first governs. The federal government may not restrict States from exercising this authority."}, {"id": "s3-6-f", "section": "§3.6.f", "name": "Vacancy Filling — States and Territories", "text": "When a House or Senate seat becomes vacant mid-term, the relevant State or Territory determines the replacement process by its own statute — special election, appointment, party nomination, or other mechanism. The Legislature sets a maximum vacancy period by statute: no State may leave a seat indefi"}, {"id": "s3-2", "section": "§3.2", "name": "The Senate — States as Constitutional Actors", "text": "The Senate — States as Constitutional Actors."}, {"id": "s3-2-c", "section": "§3.2.c", "name": "Senate Must Act on Every House Bill", "text": "The Senate must take up every House-passed bill within a defined period — indefinite Senate delay used as a de facto veto is prohibited. If the Senate fails to act within the period, the bill is deemed confirmed and passes to the executive. Senate opposition must be expressed, not implied through si"}, {"id": "s3-2-e", "section": "§3.2.e", "name": "Treaty Ratification", "text": "All international treaties require a 2/3 Senate vote. Treaties bind all States — the supermajority requirement ensures that no treaty imposes obligations without the consent of a meaningful cross-section of State representation."}, {"id": "s3-2-e-i", "section": "§3.2.e.i", "name": "Treaty Domestic Application", "text": "Ratified treaties are directly applicable as federal law in domestic courts from the date of ratification — unless the treaty requires implementing legislation or its provisions are insufficiently definite for direct judicial application. The Legislature must pass a treaty implementation framework w"}, {"id": "s3-2-e-ii", "section": "§3.2.e.ii", "name": "Treaty Withdrawal", "text": "The President may initiate withdrawal from any ratified treaty by publishing a notice of withdrawal to the NRS — specifying the treaty, the effective date (minimum six months from publication), and the grounds. The President simultaneously notifies treaty partners through diplomatic channels. Three "}, {"id": "s3-2-f", "section": "§3.2.f", "name": "Impeachment Trials", "text": "Impeachment trial conviction requires a 2/3 supermajority of seated senators — not those present. An absentee strategy to reduce the threshold through non-attendance is constitutionally closed. Removal is a constitutional act of last resort; the standard is deliberately high."}, {"id": "s3-2-g", "section": "§3.2.g", "name": "Survivor Quorum — Catastrophic Casualty Events", "text": "Where Senate membership is reduced by 50% or more in a single catastrophic event, survivors may constitute a quorum and exercise full Senate authority. A single devastating attack cannot eliminate the legislative function of government."}, {"id": "s3-2-h", "section": "§3.2.h", "name": "Senate Speaker Vacancy", "text": "When the Senate Speaker role becomes vacant — through death, resignation, expulsion, or recall — the Deputy Speaker assumes the succession role immediately. The Senate must elect a new Speaker within 72 hours. Given the Speaker is first in the presidential line of succession, the 72-hour ceiling pre"}, {"id": "s3-4", "section": "§3.4", "name": "Electoral Districts", "text": "Electoral districts for the House of the Republic are drawn through an independent commission process governed by a strict criteria hierarchy: equal population first, then geographic contiguity, then community integrity, then competitive balance. Partisan data — voting history, registration, incumbe"}, {"id": "s3-4-a", "section": "§3.4.a", "name": "Criteria Hierarchy", "text": "Districts are drawn applying criteria in order of priority: equal population first, then geographic contiguity, then community integrity, then competitive balance. A district that satisfies lower criteria while sacrificing equal population is constitutionally invalid. The ordering makes priorities e"}, {"id": "s3-4-b", "section": "§3.4.b", "name": "Prohibited Inputs", "text": "Prohibited inputs to the district-drawing process: partisan registration data, voting history by party, incumbents' home addresses, demographic projections beyond census data, and any data the LI certifies as a proxy for prohibited inputs. 'Districts whose shape requires mathematical rather than geo"}, {"id": "s4-2-ad", "section": "§4.2.a–d", "name": "Judicial Election Process", "text": "Justices are elected through the Triad process : the Senate, PM, and President each nominate one candidate from the Qualified Jurist Registry. The Judicial Inspectorate vets nominees using their submitted Registry records. All certified nominees proceed directly to national RCV election — no Senate "}, {"id": "s4-2-b", "section": "§4.2.b", "name": "Mid-Term Vacancy — 90-Day Senate Window", "text": "When a Supreme Court seat becomes vacant mid-term, the President and PM each nominate one candidate from the Registry. The Senate then has 90 days to nominate a third. If the Senate nominates in time, all three proceed to a public special election within 90 days. If the Senate fails to nominate with"}, {"id": "s4-2-d4-2-e", "section": "§4.2.d / §4.2.e", "name": "Emergency Panel and Vacancy Rules", "text": "When either executive claims the other has exceeded their domain — or when conflicting valid orders from both executives affect the same civil servants during active military operations — the Emergency Panel — four Supreme Court justices on rotating duty — resolves the dispute within 48 hours."}, {"id": "s4-2-e", "section": "§4.2.e", "name": "Vacancy Operating Rules", "text": "When a Supreme Court seat is vacant, the remaining justices continue to function. For a tied decision during a vacancy, the majority position is affirmed without precedential weight — the case is decided but the law is not settled until a full Court rules. This prevents strategic vacancy creation to"}, {"id": "s4-3-a", "section": "§4.3.a", "name": "Concrete Cases Only", "text": ""}, {"id": "s4-1-a", "section": "§4.1.a", "name": "Establishment", "text": ""}, {"id": "s4-4-a", "section": "§4.4.a", "name": "Judicial Judgments", "text": "A final judgment of any State or Territory court is entitled to recognition and enforcement throughout the Republic. States may not selectively ignore each other's court orders — a custody order from one State cannot be relitigated from scratch in another from scratch in another."}, {"id": "s4-4-b", "section": "§4.4.b", "name": "NRS Authentication", "text": "A judgment published to the NRS by the issuing court is presumptively authentic — no further authentication is needed for enforcement in another jurisdiction. The NRS eliminates the certification and verification bureaucracy that makes interstate judgment enforcement slow and expensive."}, {"id": "s4-1-b", "section": "§4.1.b", "name": "Appointment of Inferior Courts", "text": ""}, {"id": "s4-1-c", "section": "§4.1.c", "name": "Removal of Inferior Court Judges — Three Tracks", "text": "Three independent removal tracks, none displacing the others. Track 1 — Rule Violation (§2.7): Supreme Court finding triggers automatic suspension, access revocation, and Senate trial. Track 2 — Judicial Initiation: requires a 2/3 Supreme Court petition plus a legislative supermajority conviction — "}, {"id": "s5-1-a", "section": "§5.1.a", "name": "Inherent Citizenship", "text": ""}, {"id": "s5-1-a-i", "section": "§5.1.a.i", "name": "Statelessness Prevention", "text": "A child born on Republic territory to parents holding neither Citizen nor Legal Resident status is an Inhabitant from birth, with full Article I protections and BNF access. Where no country recognizes the child as a citizen, the Republic provides a determination process consistent with §6.4's protec"}, {"id": "s5-1-b", "section": "§5.1.b", "name": "Coming of Age", "text": "Children of citizens are Inhabitants at birth with full Article I protections. Full citizenship rights — including the right to vote — activate at 18. The distinction between Inhabitant and Citizen status for citizen children prevents citizenship from being used to exempt children from local law."}, {"id": "s5-1-c", "section": "§5.1.c", "name": "Naturalization", "text": "A Legal Resident may earn citizenship after five continuous years of residency, passing the Constitutional Logic Test, and demonstrating a working knowledge of the Republic's official language. The CLT tests understanding of the Republic's constitutional structure of the Republic's constitutional st"}, {"id": "s5-1-d", "section": "§5.1.d", "name": "National Service Path", "text": "A Legal Resident may earn citizenship through honorable completion of military or national service — a service path that runs parallel to the residency path. Years of service are a legitimate basis for constitutional membership."}, {"id": "s5-1-e", "section": "§5.1.e", "name": "Citizenship Irrevocability", "text": "Citizenship may not be revoked as punishment or for any reason once granted by birth or naturalization. The Republic may not manufacture statelessness as a punitive tool. See also §5.1.a.i, which ensures children born on Republic territory to undocumented parents cannot be left stateless by inaction"}, {"id": "s5-2", "section": "§5.2", "name": "Legal Resident Rights", "text": "Legal Residents hold a Residency Credential allowing them to work, enter contracts, own property, access BNF programs, and participate in local elections where the Legislature authorizes. They hold all Article I rights as Inhabitants. What they lack that citizens hold: federal voting rights and the "}, {"id": "s5-3", "section": "§5.3", "name": "Custodial Care of Citizen Children", "text": "Where a parent or guardian who is the primary caregiver of a citizen child is removed from the Republic, the Republic accepts responsibility for that citizen child — housing, care, and connection to remaining family. The Republic does not separate citizen children from their sole caregivers from the"}, {"id": "s5-4", "section": "§5.4", "name": "The Constitutional Logic Test", "text": ""}, {"id": "s5-4-a", "section": "§5.4.a", "name": "Senate Authority over the CLT Standard", "text": "The Senate establishes and maintains the CLT content and passing threshold. Raising the standard requires a simple Senate majority; lowering it requires a 2/3 supermajority. This asymmetric threshold protects the citizenship pathway from debasement through political pressure."}, {"id": "s5-5-a", "section": "§5.5.a", "name": "Automatic Citizenship Grant", "text": "All individuals holding voting rights on Day Zero of ratification are automatically granted full citizenship without testing or application. The Day Zero Grandfather Clause prevents the new Republic from immediately disenfranchising its existing population by requiring existing voters to re-qualify "}, {"id": "s6-1-ab", "section": "§6.1.a–b", "name": "The Dual Gate", "text": "Legal residency requires passing both gates. Neither gate alone is sufficient — both must be satisfied . The dual-gate architecture prevents both federal overreach and State capture."}, {"id": "s6-1-c", "section": "§6.1.c", "name": "Presidential Role", "text": "Once an applicant clears both gates, the President must ministerially issue residency credentials. The word 'ministerially' is deliberate — the President has no discretion to refuse or delay what the law requires. Presidential interference with credential issuance constitutes a Rule Violation."}, {"id": "s6-1-d", "section": "§6.1.d", "name": "Federal Sponsorship Category", "text": "The Legislature may establish a Federal Sponsorship Category where designated federal agencies serve as Gate 1 sponsors for applicants whose skills directly serve a defined federal interest — research programs, national infrastructure, national security-adjacent technical roles. The agency assumes a"}, {"id": "s6-2", "section": "§6.2", "name": "Enforcement and Removal", "text": "Only the Federal government may remove individuals from the Republic — States may not conduct deportations. Removal occurs only for violations of laws the Legislature has defined."}, {"id": "s6-3", "section": "§6.3", "name": "Gate 2 Appeal Rights", "text": "Gate 2 denials are judicially challengeable on three grounds: the denial relied on a criterion outside the four certified categories; the denial was discriminatory contrary to §1.8; or the stated ground is factually unsupported by the evidence used. Gate 1 denials — a State's decision not to sponsor"}, {"id": "s6-3-b", "section": "§6.3.b", "name": "National Security Denials — In-Camera Review", "text": "Where Gate 2 is denied on national security grounds, a reviewing court may examine the classified assessment in camera and determine whether it constitutes a credible, specific, and documented concern — without publishing classified content. The in-camera review is outcome-determinative: either the "}, {"id": "s6-3", "section": "§6.3", "name": "Application Appeals", "text": "Gate 2 denials are subject to judicial challenge on three grounds: the denial relied on factually inaccurate information; the denial applied a standard not authorized by law; or the denial violated Article I. The national security track routes in-camera to a security-cleared judge. The three-grounds"}, {"id": "s6-4", "section": "§6.4", "name": "Asylum and Protection", "text": "Seven sub-provisions governing the asylum and protection framework: asylum seekers as BNF Inhabitants from filing date; right to determination before removal; the Asylum Court as a constitutionally independent judicial body under Article IV — not an executive tribunal . Non-penalization for irregula"}, {"id": "s6-4-a", "section": "§6.4.a", "name": "Asylum Seekers as Inhabitants", "text": "Any person who files an asylum claim under §1.27 is an Inhabitant of the Republic from the date of filing — immediately entitled to BNF coverage and all Article I protections. Protection-first: the determination process does not happen in a rights-free zone."}, {"id": "s6-4-b", "section": "§6.4.b", "name": "Right to Determination and Protection During Proceedings", "text": ""}, {"id": "s6-4-c", "section": "§6.4.c", "name": "Asylum Court", "text": "The Asylum Court is a federal judicial institution constitutionally independent of both executive branches. Its judges hold full tenure protections. The Legislature may not establish any asylum determination body as a subdivision or instrumentality of either executive branch — administrative asylum "}, {"id": "s6-4-d", "section": "§6.4.d", "name": "Non-Penalization for Irregular Entry", "text": "The manner or means of entry into the Republic — including irregular or unauthorized entry — does not affect the right to claim asylum or have that claim determined. No penalty arising solely from irregular entry may be imposed on a person whose asylum claim is pending or has been granted."}, {"id": "s6-4-f", "section": "§6.4.f", "name": "Security and Criminal Protection Cases", "text": "Where the Asylum Court grants §1.27 protection to a person who poses a documented security threat, removal remains constitutionally barred — but indefinite unreviewed detention is not constitutionally available. The Legislature must establish a framework with regular judicial review. 'Indefinite unr"}, {"id": "s6-4-h", "section": "§6.4.h", "name": "Unaccompanied Minors", "text": "An unaccompanied minor arriving in the Republic or presenting to Republic authorities is an Inhabitant from the moment of contact and holds full §1.27 protection. A federal legal guardian must be appointed within 24 hours. No unaccompanied minor may be detained in a facility not specifically designa"}, {"id": "s7-2-a", "section": "§7.2.a", "name": "National Ranked-Choice Vote", "text": "Presidential elections use ranked-choice voting nationally. Votes transfer until one candidate achieves a national majority."}, {"id": "s7-2-b", "section": "§7.2.b", "name": "The Combined Score", "text": "Where no candidate achieves a national majority, the winner has the highest combined score — national vote share plus State-weighted electoral count ."}, {"id": "s7-2-c", "section": "§7.2.c", "name": "Presidential Election Regions", "text": "The Republic is divided into presidential election regions to provide the geographic breadth component of the combined score. At least three regions are required; no more than one per ten States once the Republic exceeds thirty States. The Legislature draws regions; the LI reviews for compliance."}, {"id": "s7-2-d", "section": "§7.2.d", "name": "Territory Presidential Voting", "text": "Territory citizens hold the full §1.19 right to vote in presidential elections. Their votes count in the national first-preference total — the 65% component of the combined score — but Territories are not assigned to presidential election regions and do not contribute to the 35% regional breadth com"}, {"id": "s7-2-e", "section": "§7.2.e", "name": "Election Certification", "text": "The Electoral Commission certifies the final presidential election result to the NRS within a period the Legislature defines by statute. Certification is final and may be challenged only before the Supreme Court within 14 days. No transfer of presidential authority may be delayed beyond the constitu"}, {"id": "s7-2-f", "section": "§7.2.f", "name": "Run-off", "text": "If two candidates are within 0.5% of each other on the combined score, a head-to-head national RCV runoff is conducted between those two candidates. The runoff closes the edge-case gap where the combined score is mathematically indeterminate."}, {"id": "s7-3-a", "section": "§7.3.a", "name": "No Executive Interference", "text": "The President may not declare, postpone, or influence the scheduling of elections — including declaring emergencies that have the effect of postponing them. §1.25.e's prohibition on emergency-based election postponement backs this up: even a genuine emergency cannot defer a scheduled election."}, {"id": "s7-3-b", "section": "§7.3.b", "name": "National Voting System", "text": "The Electoral Commission administers the National Voting System through which all federal elections and referenda are conducted. The NVS is constitutionally required to maintain ballot secrecy, public auditability, and resilience — properties defined in Article XVI creating a cross-constitutional gu"}, {"id": "s7-3-c", "section": "§7.3.c", "name": "Participation Protection", "text": "No State may take any action that reduces NVS access, functionality, or availability within its territory. State-level voter suppression — long lines, ID requirements that function as bars, polling place closures that reduce access — is constitutionally prohibited to the extent it reduces access for"}, {"id": "s8-1", "section": "§8.1", "name": "Three Inspectorates", "text": "Three permanent, constitutionally established Inspectorates — Legislative (§8.1.a), Executive (§8.1.b), and Judicial (§8.1.c) — each audit a different branch of government. None has enforcement power: their mandate is information, not action. All findings are published permanently to the NRS. Their "}, {"id": "s8-1-a", "section": "§8.1.a", "name": "The Legislative Inspectorate (LI)", "text": "The Legislative Inspectorate audits the House and Senate for fiscal accuracy, constitutional compliance of enacted legislation, redistricting compliance, and BNF provision rates at the State level. The LI is not selected by the legislative branch it audits — its IG is nominated by the Supreme Court "}, {"id": "s8-1-b", "section": "§8.1.b", "name": "The Executive Inspectorate (EI)", "text": "The Executive Inspectorate audits both executive offices and the Monetary Authority for constitutional compliance and rule violation evidence. For appointed positions, the EI reviews candidate disclosure records submitted by the nominating actor — it does not generate independent assessments — and p"}, {"id": "s8-1-c", "section": "§8.1.c", "name": "The Judicial Inspectorate (JI)", "text": "The Judicial Inspectorate audits the court system for compliance with judicial scope and independence standards, maintains the Qualified Jurist Registry (candidates submit their own registration records; the JI reviews for accuracy and applies criteria), and audits the Electoral Commission. Its IG i"}, {"id": "s8-3-a", "section": "§8.3.a", "name": "Legislative IG", "text": "The Legislative IG is nominated by the Supreme Court and confirmed by the Senate with a 2/3 supermajority. Nomination by the judiciary — itself independent of the Legislature — gives the LI's leadership genuine independence from the institution it audits."}, {"id": "s8-3-b", "section": "§8.3.b", "name": "Executive IG", "text": "The Executive IG is nominated by the House and confirmed by the Senate. Neither executive nominates or confirms the body that audits them. The deemed confirmed provision prevents either chamber from blocking an IG appointment through indefinite inaction."}, {"id": "s8-5-a", "section": "§8.5.a", "name": "For-Cause Removal", "text": "For-Cause IG removal requires a 2/3 supermajority of both chambers simultaneously. Before the Legislature may vote, the State Designee Panel — a rotating body of five State-appointed representatives drawn by lot — publishes a binary verification finding on whether stated grounds are substantiated. G"}, {"id": "s8-5-b", "section": "§8.5.b", "name": "No-Cause Removal", "text": "No-cause removal requires a 3/4 vote of both chambers simultaneously — the extraordinary supermajority signals that no-cause removal is a constitutional last resort, not a political convenience. The mandatory 90-day delay between vote and removal allows judicial challenge of politically motivated re"}, {"id": "s8-6-a", "section": "§8.6.a", "name": "Reports", "text": "Each Inspectorate publishes its findings as formal Reports to the NRS — permanent, unalterable, publicly accessible from publication. Reports cover every audit, investigation, and non-pursuit decision. Inspectorate work is the property of the public, not the institution being audited."}, {"id": "s8-6-b", "section": "§8.6.b", "name": "No Classification", "text": "Inspectorate Reports are permanently exempt from classification. Even where an investigation touches classified matters, the finding itself must still be published. Classification may not be used to suppress accountability findings."}, {"id": "s8-6-c", "section": "§8.6.c", "name": "No Binding Force", "text": "Inspectorate findings carry no binding legal force on their own — they are published to the NRS and create political accountability, not legal commands."}, {"id": "s8-6-d", "section": "§8.6.d", "name": "Non-Pursuit Disclosure", "text": "Every decision not to open an investigation following a valid trigger must be published to the NRS with the reasoning. Non-pursuit disclosure closes the suppression-by-inaction pathway — an Inspectorate cannot simply decline to investigate a problem and remain silent about the decision."}, {"id": "s8-6-e", "section": "§8.6.e", "name": "Minority Reports", "text": ""}, {"id": "s8-6-f", "section": "§8.6.f", "name": "Inspectorate Funding Guarantee", "text": "Cross-reference: see §8.10 for the constitutional minimum funding guarantee. Inspectorate funding cannot be reduced below prior year without a 2/3 vote of both chambers."}, {"id": "s8-6-g", "section": "§8.6.g", "name": "Citizen Discrepancy Petition", "text": "Any citizen who identifies a factual discrepancy in a candidate disclosure record or Registry registration record published to the NRS may petition their elected House member or Senator in writing. No fee, threshold, or filing requirement may be imposed. The elected representative may raise the matt"}, {"id": "s8-9", "section": "§8.9", "name": "Inspectorate Oversight — State Designee Panel", "text": "For-Cause IG removal verification is performed by the State Designee Panel — five State-appointed representatives drawn by lot at each two-year election cycle, with two alternates. The Panel's sole constitutional function is verifying whether For-Cause removal grounds are substantiated before the Le"}, {"id": "s8-9", "section": "§8.9", "name": "State Designee Panel — Composition", "text": "Each State and Territory maintains one standing designee for this function, published to the NRS. Federal floor: citizen, no current federal office, no judicial office, no Inspectorate employment. The Electoral Commission draws the five-member panel and two alternates by lot at the start of each two"}, {"id": "s8-11", "section": "§8.11", "name": "Eighth-Year Assessment", "text": "Every eight years, the three Inspectorates jointly publish a comprehensive assessment of the constitutional order — the constitutional system auditing itself."}, {"id": "s9-1", "section": "§9.1", "name": "NRS Properties", "text": "The National Record System is the Republic's single source of constitutional truth — every constitutionally required publication finds its permanent, unalterable record here."}, {"id": "s9-1-a", "section": "§9.1.a", "name": "Immutability", "text": "All NRS entries are permanent — they may never be deleted or altered after confirmation. Superseded records are annotated with the superseding record; the original remains. The immutability is the technical foundation for the Republic's accountability architecture: politicians cannot disappear incon"}, {"id": "s9-1-b", "section": "§9.1.b", "name": "Distributed Custody", "text": "The NRS is maintained by a network of independent, constitutionally mandated nodes — not a single central server under government control. Each Inspectorate and each State operates at least one independent node. No single point of failure, no single point of control, no single point of government ca"}, {"id": "s9-1-c", "section": "§9.1.c", "name": "Public Accessibility", "text": "All NRS entries must be readable by any Inhabitant at no cost and without registration. The accessibility requirement is independently mandated from the operational requirement — a system that technically operates but is practically inaccessible fails both. The NRS is the Republic's public square fo"}, {"id": "s9-1-e", "section": "§9.1.e", "name": "Technology Neutrality", "text": "No specific technology, protocol, or cryptographic standard is named in this Constitution. The NRS must have defined properties — immutability, distribution, public accessibility, cryptographic signing — and technology must meet those properties. This technology neutrality ensures the constitution d"}, {"id": "s9-3", "section": "§9.3", "name": "RSA Director", "text": "The RSA Director is nominated by the Prime Minister from a Candidate Register maintained under the same mechanism as §10.4.a — the Executive Inspectorate publishes a factual assessment of each candidate's professional background and relevant expertise to the..."}, {"id": "s9-1-g", "section": "§9.1.g", "name": "NRS Self-Authentication", "text": "All records published to the National Record System pursuant to a constitutional mandate are self-authenticating in any constitutional or legal proceeding. No additional foundation laying, certification, apostille, or authentication process may be required..."}, {"id": "s9-2", "section": "§9.2", "name": "Node Operators", "text": "Each Inspectorate and each State must operate at least one independent node. The Legislature may charter additional nodes from civil society, universities, or international organizations. Independence — meaning free from centralized manipulation — is a constitutional property, not a technical prefer"}, {"id": "s9-4-a", "section": "§9.4.a", "name": "Classification Authority", "text": ""}, {"id": "s9-4-b", "section": "§9.4.b", "name": "Classification Duration", "text": "Standard classification expires 10 years from creation without renewal — and renewal must be separately justified. Automatic declassification prevents the indefinite accumulation of secret government records that characterizes most existing classification systems."}, {"id": "s9-4-c", "section": "§9.4.c", "name": "Classification Registry", "text": "The existence of every classified document must be registered on the NRS — even if its contents remain classified. Citizens know that classified information exists even if they cannot access it. No secret program can exist without its existence being publicly acknowledged."}, {"id": "s9-4-d", "section": "§9.4.d", "name": "Automatic Declassification", "text": "Upon expiration of classification without renewal, all affected documents transfer automatically to the NRS with full public accessibility. No action is required — declassification is the automatic outcome of inaction. Secrecy requires active maintenance, not transparency."}, {"id": "s9-4-e", "section": "§9.4.e", "name": "Improper Classification", "text": "Classification used to conceal a Rule Violation, an illegal order, or embarrassing but non-sensitive information constitutes a Rule Violation in itself. Improper classification is not an administrative error — it is a constitutional offense — it is a constitutional offense."}, {"id": "s10-1", "section": "§10.1", "name": "The Basic Needs Floor", "text": "A constitutionally guaranteed minimum of provision — housing, healthcare, food security, education, and social protection — indexed to the Republic's actual economic capacity."}, {"id": "s10-1-a", "section": "§10.1.a", "name": "Anti-Evasion Principle", "text": "The BNF guarantees actual provision, not a formula satisfied on paper. The anti-evasion principle prohibits reclassification, formula manipulation, and creative accounting . The MA's certification detects structural evasion."}, {"id": "s10-1-d", "section": "§10.1.d", "name": "Severe Contraction Protocol — Activation", "text": "When the MA certifies that current gross revenue has fallen 25% below baseline in any fiscal year, the Severe Contraction Protocol activates automatically. Activation is not a political decision — it is a certification finding. The protocol allows the BNF floor to contract proportionally to actual e"}, {"id": "s10-1-e", "section": "§10.1.e", "name": "Severe Contraction Protocol — Effects", "text": "During a certified Severe Contraction, the BNF floor may be reduced proportionally — but never below a Severe Contraction minimum defined in statute. Even in crisis, equality of reduced provision is constitutionally mandated — the contraction cannot be used to differentially reduce provision for par"}, {"id": "s10-1-f", "section": "§10.1.f", "name": "Severe Contraction Protocol — Parliamentary Review", "text": "The Legislative Inspectorate reviews every Severe Contraction certification within 45 days and publishes a compliance report. The Legislature must hold a debate within 30 days of the LI report. If the Legislature finds the contraction is being used to target specific groups or evade the anti-evasion"}, {"id": "s10-1-g", "section": "§10.1.g", "name": "Federal Supplementation Obligation", "text": ""}, {"id": "s10-4-a", "section": "§10.4.a", "name": "MA Director — Elected Office", "text": ""}, {"id": "s10-2", "section": "§10.2", "name": "Taxation Authority", "text": "Taxation authority originates exclusively in the House — no tax bill may originate in the Senate. The Fiscal Objection mechanism (§2.4.b) gives the PM a specialized check on tax legislation distinct from the ordinary suspensive veto. Within those constraints, the Legislature has broad authority to s"}, {"id": "s10-2-a", "section": "§10.2.a", "name": "Tax Origination and Fiscal Objection", "text": "Tax bills must originate in the House of the Republic. The PM may issue a Fiscal Objection — separate from the ordinary suspensive veto — on grounds that a bill creates fiscal obligations the Republic cannot meet without BNF evasion or unauthorized deficit. A Fiscal Objection returns the bill with a"}, {"id": "s10-2-b", "section": "§10.2.b", "name": "Annual Budget and Continuation Spending", "text": "the Legislature must pass an annual budget. Where the Legislature fails to pass a budget before the start of the fiscal year, a Continuation Spending Order automatically takes effect — maintaining prior-year spending levels at the BNF-adjusted rate for a period the Legislature defines by statute. Th"}, {"id": "s10-3", "section": "§10.3", "name": "Deficit Controls", "text": "The Republic may not spend beyond projected revenue in any fiscal year without a 3/4 vote of both chambers simultaneously — the same extraordinary supermajority required for no-cause IG removal. This is a deliberate constitutional barrier to deficit spending. The BNF and Severe Contraction spending "}, {"id": "s10-3-a", "section": "§10.3.a", "name": "Inherited Deficit Transition Threshold", "text": "During any fiscal year in which the Republic's debt-to-GNR ratio exceeds the Inherited Deficit Threshold the MA certifies, the Legislature may run a controlled deficit by 2/3 vote rather than 3/4, provided the ratio is declining. This transitional provision prevents the new Republic from being immed"}, {"id": "s10-3-b", "section": "§10.3.b", "name": "BNF and Contraction Exemptions", "text": "The Basic Needs Floor and Severe Contraction supplementation obligations are exempted from deficit calculations during their respective activation periods. Constitutional fiscal obligations take precedence over constitutional fiscal limits — the hierarchy is explicit rather than left to judicial int"}, {"id": "s10-4-b", "section": "§10.4.b", "name": "MA Independence", "text": "The Monetary Authority operates with constitutional independence from both executives . Neither may direct its certifications, modify its findings, or remove its Director except through the constitutional process."}, {"id": "s10-4-c", "section": "§10.4.c", "name": "Transparency", "text": "The MA must publish all decisions, models, and revenue assessments to the NRS in real time — including the models it uses to calculate GNR. The transparency mandate makes the MA's methodology auditable by anyone, closing the black-box fiscal assessment pathway."}, {"id": "s10-4-d", "section": "§10.4.d", "name": "Methodology Integrity", "text": "The MA's calculation methodology must use a single, consistent definition of GNR for all constitutional formula applications. The Legislature cannot define GNR differently for BNF calculations than for deficit calculations than for supplementation triggers. Formula manipulation through definitional "}, {"id": "s10-5-a", "section": "§10.5.a", "name": "Official Benefits", "text": "The Republic provides standardized housing for officials in session — no luxury differential, no official residences that become perks of office. Official time and official resources are for official purposes."}, {"id": "s10-5-b", "section": "§10.5.b", "name": "Financial Disclosure", "text": "Every elected and appointed official must file a complete public financial disclosure within 30 days of taking office and annually thereafter. Disclosures are published to the NRS within 7 days of filing. Failure to file on time, material omission, or knowing misstatement is a Rule Violation , mater"}, {"id": "s10-5-c", "section": "§10.5.c", "name": "Integrity Bans", "text": "Officials are subject to a post-service lobbying ban of not less than five years. The Legislature may extend the ban but may not reduce it below five years. The minimum is constitutionally entrenched to prevent future parliaments from eroding the revolving-door restriction under lobbying pressure."}, {"id": "s10-5-d", "section": "§10.5.d", "name": "Anti-Ego Provision", "text": "No public works, buildings, programs, or infrastructure may be named after any living official or any person who held public office within a recent period defined by House statute. Exception: officials who die in service to the Republic may be honored by a..."}, {"id": "s10-5-h", "section": "§10.5.h", "name": "Oath of Office Requirement", "text": "Every official of the Federated Republic — elected, appointed, or career — must swear or affirm the constitutional oath before exercising any official function. The oath is a constitutional requirement, not a ceremony: an official who has not taken the oath holds no lawful authority."}, {"id": "s10-6-a", "section": "§10.6.a", "name": "Jury Duty", "text": "Citizens must serve on juries when called, compensated at the national median daily wage. Jury service is the one form of compelled service the constitution permits — §1.3's prohibition on forced labor explicitly carves it out. Compensation prevents jury service from being an economic hardship conce"}, {"id": "s11-1", "section": "§11.1", "name": "Optional Referendum", "text": "Citizens may petition for an Optional Referendum on any enacted statute. The Legislature may repeal before the referendum; if not, the result is binding."}, {"id": "s11-1-a", "section": "§11.1.a", "name": "Citizen Petition Right", "text": "Citizens may pause the implementation of any newly enacted law by submitting verified signatures of 5% of eligible voters within 90 days of enactment. The 5% threshold requires genuine popular mobilization. The pause goes into effect immediately upon certification, preventing the law from being entr"}, {"id": "s11-1-b", "section": "§11.1.b", "name": "Eligibility Screen", "text": "Before certification, the Judicial Inspectorate screens the petition for eligibility — ensuring the law is referendum-eligible, that the signatures are genuine, and that the petition was filed within the window. The screening protects against procedural abuse without making certification a substanti"}, {"id": "s11-1-c", "section": "§11.1.c", "name": "Referendum Thresholds and Finality", "text": "A referendum requires 50% participation to be valid — the participation floor ensures the result represents genuine democratic engagement , not a mobilized minority. A simple majority affirmative vote overturns the law. The Legislature may not re-enact substantially identical legislation within two "}, {"id": "s11-2-a", "section": "§11.2.a", "name": "Subsidiarity Principle", "text": "Government makes decisions at the lowest level of governance capable of effectively addressing the matter . The subsidiarity principle is justiciable."}, {"id": "s11-2-b", "section": "§11.2.b", "name": "Local Government", "text": "Local governments — cities, counties, municipalities, and other subdivisions — receive constitutional recognition as the primary points of contact between citizens and government. They are entitled to reasonable fiscal capacity to carry out their constitutional functions. States may not starve local"}, {"id": "s12-2", "section": "§12.2", "name": "Legislative Declaration of Defense", "text": "Military authorization operates on three tiers. Tier 1 (immediate defensive response) requires no prior approval but must be notified within 6 hours and authorized by the SASC within 72. Tier 2 (Senate Armed Services Committee) covers offensive operations and transitional deployments. Tier 3 (Legisl"}, {"id": "s12-2-a", "section": "§12.2.a", "name": "Legislative Declaration of Defense", "text": "A Legislative Declaration of Defense requires a 2/3 concurrent majority of both chambers simultaneously — one of the highest thresholds in the document. The concurrent requirement means the House and Senate must vote on the same Declaration; sequential approval where one chamber can walk back the ot"}, {"id": "s12-2-b", "section": "§12.2.b", "name": "Five-Year Maximum", "text": ""}, {"id": "s12-2-c", "section": "§12.2.c", "name": "Successive Declaration Standard", "text": "A new Legislative Declaration of Defense issued within 12 months of a mandatory cessation must be based on a materially different threat — a distinct adversary, different geographic theater, or qualitatively different form of attack. Not a resumption of the same conflict under a different pretext. T"}, {"id": "s12-3", "section": "§12.3", "name": "Intelligence Firewall", "text": "All domestic intelligence operations against Republic citizens are permanently prohibited — the single clearest line in Article XII. Any order for domestic surveillance of Republic citizens is an automatic Rule Violation for the President and Director of Intelligence under §2.1.e, triggering immedia"}, {"id": "s12-2-d", "section": "§12.2.d", "name": "Senate Armed Services Committee", "text": "The Senate Armed Services Committee exercises Tier 2 military authorization. SASC authorization must happen within 72 hours of presidential notification. When the presidential succession line is active, the SASC Chairman is the first civilian authority to whom military commanders report."}, {"id": "s12-2-e", "section": "§12.2.e", "name": "Military Authority During Presidential Succession Vacuum", "text": "When the presidential succession line is fully exhausted, the Chairman of the Joint Chiefs may continue operations already underway and issue orders strictly necessary to protect Republic forces from active, immediate attack — return fire and immediate defensive maneuvering only. No initiation, repo"}, {"id": "s12-1", "section": "§12.1", "name": "Authorized Purposes for Military Force", "text": "The Republic authorizes military force for three and only three purposes: defense of the Republic's territory from armed attack, protection of Republic citizens abroad facing imminent threat, and fulfillment of ratified mutual defense treaty obligations. Nation-building, resource extraction, ideolog"}, {"id": "s12-4", "section": "§12.4", "name": "Military Accountability", "text": "Extended occupations — deployments lasting more than 10 years without Senate-approved renewal — are unconstitutional and must terminate within 90 days. Inhabitants of any territory under Republic military occupation for more than one year may petition to join the Republic through the §13.6 voluntary"}, {"id": "s12-5-a", "section": "§12.5.a", "name": "Treaty Emergency Certification", "text": "When a ratified mutual defense treaty is triggered by an attack on a treaty partner, the PM may issue a Treaty Emergency Certification within 48 hours. The PM's certification initiates the parliamentary authorization process; it does not authorize military action by itself."}, {"id": "s12-5-c", "section": "§12.5.c", "name": "No Blank Check", "text": "The Treaty Emergency Certification covers operational costs for the initial response and triggers parliamentary authorization for any extended engagement. Treaties cannot be blank checks for extended military commitment for extended military commitment — each sustained engagement requires parliament"}, {"id": "s13-4", "section": "§13.4", "name": "Voluntary Devolution", "text": "A State may choose to become a Territory through a voluntary devolution referendum requiring a two-thirds vote of residents with a minimum 10-year Citizen Voting Credential . The constitutional pathway runs inward as well as outward — the threshold is two-thirds, consistent with other significant co"}, {"id": "s13-4-b", "section": "§13.4.b", "name": "Fiscal Transparency Requirement", "text": "Before a voluntary devolution vote, the MA must publish a Fiscal Incidence Study showing what the State currently pays and receives from the federal system, and what it would pay and receive as a Territory. Citizens vote on the basis of accurate information about the economic consequences."}, {"id": "s13-4-c", "section": "§13.4.c", "name": "Net-Contributor Transparency", "text": "Where the Fiscal Incidence Study finds the State is a net contributor to the federal system, that finding must appear in plain language on the ballot itself . Citizens choosing voluntary devolution must be explicitly informed if they are choosing to give up net federal fiscal benefits."}, {"id": "s13-5", "section": "§13.5", "name": "Associated Community Relationships", "text": "Associated Community status — the constitutional framework governing compact relationships with sovereign entities — is governed exclusively by Article XX. Article XIII governs inward relationships (Territories and States); Article XX governs outward relationships (sovereign nations in compact). The"}, {"id": "s13-6", "section": "§13.6", "name": "Voluntary Incorporation", "text": "The inbound pathway the document previously lacked — a sovereign entity voluntarily joining the Republic's constitutional framework as a Territory . Requires 2/3 legislature, confirmatory referendum, JI assessment, and 2/3 parliamentary acceptance."}, {"id": "s13-2", "section": "§13.2", "name": "The Statehood Audit", "text": "Territories become States by passing the Statehood Audit — a comprehensive assessment by the three Inspectorates covering fiscal integrity, legal synchronization with the Individual Sovereignty Floor, democratic legitimacy, institutional capacity, and NRS connectivity. The audit is not a political v"}, {"id": "s13-2-c", "section": "§13.2.c", "name": "The Provisional Membership Period", "text": "Upon passing the Statehood Audit, a territory enters a Provisional Membership Period during which it sends non-voting observers to both chambers. House seats are allocated by population; Senate seats activate at full Statehood. The Provisional Membership Period creates a structured transition rather"}, {"id": "s13-2-e", "section": "§13.2.e", "name": "Minimum Democratic Legitimacy", "text": "Three functional requirements every State must maintain: electoral accountability, judicial independence, and public law governance . Both EC technical certification and LI political assessment are required."}, {"id": "s13-2-f", "section": "§13.2.f", "name": "Territorial Minimum Institutional Floor", "text": "Every Territory must maintain: (1) a governance council with defined membership and published authority; (2) resident access to federal judicial review of executive action; and (3) direct enforcement of Article I rights for all Territorial residents by..."}, {"id": "s13-2-g", "section": "§13.2.g", "name": "Conflict-Affected State Provisional Status", "text": "Protects States in genuine crisis without sheltering States whose governance created the crisis . Joint Inspectorate assessment, five-year maximum, and default joint administration close exploitable pathways."}, {"id": "s13-3", "section": "§13.3", "name": "Mandatory Devolution", "text": "Mandatory State Devolution is the constitutional consequence of sustained audit failure — three consecutive years of failing the Statehood Audit trigger a Senate Motion of Devolution. The Early Warning system (§13.3.b) provides two years of remediation before Devolution is considered. The 3/4 Senate"}, {"id": "s13-3-b", "section": "§13.3.b", "name": "Early Warning — Years 1 and 2", "text": "Upon a first consecutive audit failure, the LI publishes a State Remediation Plan — a specific, actionable set of requirements for restoring compliance. The State has 24 months to implement before the next audit. Early Warning is the document's anti-failure mechanism: most States that enter it never"}, {"id": "s13-3-c", "section": "§13.3.c", "name": "Devolution Vote — Year 3", "text": "Upon the third consecutive audit failure, the Senate votes on a Motion of Devolution requiring a 3/4 supermajority. The high threshold means Mandatory Devolution requires near-consensus in the States' chamber — it cannot be used as a political weapon against a State by a partisan majority."}, {"id": "s13-3-d", "section": "§13.3.d", "name": "Effect of Mandatory Devolution", "text": "A devolved State loses its Senate seats on the date the Devolution Motion passes. It retains House seats proportional to population. Federal law continues to apply. The State government continues as territorial administration under federal oversight. All effects are published to the NRS the moment t"}, {"id": "s14-5-d", "section": "§14.5.d", "name": "Pre-Existing Sovereignty Pathway", "text": "An indigenous nation whose sovereignty is constitutionally recognized under Article XIV may petition for Associated Community status under Article XX without completing the independence process. The pathway acknowledges that recognized sovereign nations need not gain formal independence they already"}, {"id": "s14-3-a", "section": "§14.3.a", "name": "Free, Prior, and Informed Consent", "text": "The Republic may not take any action affecting indigenous lands or sovereignty without free, prior, and informed consent from the affected indigenous nation."}, {"id": "s14-3-b", "section": "§14.3.b", "name": "Unamendable Rights Override", "text": "The FPIC requirement does not apply to enforcement of the six permanently unamendable provisions within indigenous jurisdictions. These six rights can be enforced without indigenous consent — they represent the floor below which even negotiated sovereignty cannot go. The Republic can enforce freedom"}, {"id": "s14-3-c", "section": "§14.3.c", "name": "Emergency Rights Writ", "text": ""}, {"id": "s14-3-d", "section": "§14.3.d", "name": "Internal Enforcement Support", "text": "With the consent of the relevant indigenous nation, the Republic may provide technical or financial support for the development of internal rights enforcement mechanisms within the nation's own legal traditions. The operative word is consent — the Republic may not unilaterally impose an enforcement "}, {"id": "s14-3-e", "section": "§14.3.e", "name": "Inspectorate Jurisdiction Limit", "text": "The Inspectorates' audit jurisdiction does not extend to the internal governance of indigenous nations — with one exception: where a specific allegation of violation of a permanently unamendable provision is made against an individual member, the Supreme Court has jurisdiction on petition. The scope"}, {"id": "s14-1", "section": "§14.1", "name": "Acknowledgment of Prior Sovereignty", "text": ""}, {"id": "s14-4-a", "section": "§14.4.a", "name": "Eminent Domain Prohibition", "text": "The Republic may not acquire indigenous lands by eminent domain or any other mechanism without the voluntary consent of the indigenous nation, expressed through a free democratic act following full disclosure of purpose, scope, and compensation. No national security exception, no emergency exception"}, {"id": "s14-4-b", "section": "§14.4.b", "name": "Conservation Trust", "text": "The Republic may not designate indigenous lands as National Trust or conservation lands without the indigenous nation's consent. Conservation designation cannot be used to effectively dispossess an indigenous nation of management authority while leaving nominal ownership intact."}, {"id": "s14-5-a", "section": "§14.5.a", "name": "Article I Rights", "text": "Every individual member of an indigenous nation is an Inhabitant of the Republic and holds the full protections of Article I, enforceable directly by federal courts regardless of the nation's internal governance structure. Indigenous nations hold collective sovereignty; their members hold individual"}, {"id": "s14-5-b", "section": "§14.5.b", "name": "Dual Citizenship", "text": ""}, {"id": "s14-5-c", "section": "§14.5.c", "name": "National Voting System — Voluntary Connection", "text": "Indigenous nations may voluntarily connect to the National Voting System for their members' participation in Republic-level elections. Connection is not compelled — the NVS infrastructure is available; its use is the nation's choice. The electoral infrastructure of indigenous nations for their own i"}, {"id": "s14-2", "section": "§14.2", "name": "Treaty Supremacy and Continuity", "text": "All treaties entered into by predecessor governments with indigenous nations are binding obligations of the Republic. Treaty rights cannot be diminished by legislation — they must be honored, renegotiated with consent, or formally superseded through the FPIC framework."}, {"id": "s15-1", "section": "§15.1", "name": "Two Amendment Paths", "text": "Three amendment paths, each calibrated to the nature and significance of the change. §15.1.a Parliamentary alone (3/4 of both chambers — for technical corrections); §15.1.b Parliamentary with popular confirmation (2/3 of both chambers plus 55% national vote / 55% participation — for significant chan"}, {"id": "s15-1-a", "section": "§15.1.a", "name": "Parliamentary Path", "text": "Ratification by a three-quarters supermajority of the full seated membership of both chambers simultaneously. Individual voting records published to the NRS within 24 hours. Appropriate for technical corrections, gap-filling, and amendments with broad cross-party consensus."}, {"id": "s15-1-b", "section": "§15.1.b", "name": "Parliamentary and Popular Path", "text": "A two-thirds supermajority of both chambers, followed by a national popular vote achieving 55% affirmative support with 55% participation. The Legislature leads; the people confirm. The popular vote must be held within 180 days of the legislative vote. For significant constitutional changes where de"}, {"id": "s15-1-c", "section": "§15.1.c", "name": "Citizen-Led Path", "text": "A national vote achieving 70% affirmative support with 65% participation. The highest threshold — for constitutional changes the people wish to make when the Legislature will not act. The Electoral Commission certifies the result; any person with standing may challenge it before the Supreme Court wi"}, {"id": "s15-3-a", "section": "§15.3.a", "name": "Permanently Unamendable Provisions", "text": "Six provisions are permanently unamendable : the prohibitions on torture (§1.2), slavery (§1.3), and non-refoulement (§1.27); habeas corpus (§1.13); the right to a public trial (§1.17); and the prohibition on retroactive punishment (§1.18). These may not be altered, qualified, or removed by any amen"}, {"id": "s15-4-a", "section": "§15.4.a", "name": "Territorial Integrity", "text": "The territorial integrity of the Republic is not subject to unilateral dissolution. A State may not simply declare independence — the pathway requires: an advisory referendum, then a negotiated Framework Agreement, then formal independence under §15.5. The structured process prevents both secessioni"}, {"id": "s15-4-a", "section": "§15.4.a", "name": "Independence — The 70% National Vote Requirement", "text": "Independence from the Republic requires 70% affirmative support in a national popular vote via the National Voting System with at least 65% participation. The threshold is national — not the departing territory's vote alone. This is the constitution's most demanding supermajority: higher than any am"}, {"id": "s15-5-e", "section": "§15.5.e", "name": "Simultaneous Independence Sequencing", "text": "Where more than one independence process is simultaneously authorised under §15.4, transition periods must be sequenced with a minimum interval between formal independence dates that the Legislature defines by statute. Sequencing must be specified in each..."}, {"id": "s15-6", "section": "§15.6", "name": "Supremacy of This Constitution", "text": "This Constitution is the supreme law of the Federated Republic. All legislative acts, executive orders, treaties, administrative decisions, and government actions of any kind must be consistent with it. Any provision of law inconsistent with this Constitution is, to the extent of the inconsistency, "}, {"id": "s15-6-b", "section": "§15.6.b", "name": "Federal-State Statutory Hierarchy", "text": "Federal statutes enacted within the Legislature's constitutional competence prevail over conflicting State statutes. Where federal and State statutes address the same subject without conflict — where a person can comply with both simultaneously — both operate concurrently and the State statute is no"}, {"id": "s15-2", "section": "§15.2", "name": "No Executive Veto Over Amendments", "text": "Neither the President nor the Prime Minister holds veto authority over constitutional amendments. Amendments take immediate effect when the Inspectorates certify ratification under any of the three amendment paths of §15.1 and record the amendment on the National Record System."}, {"id": "s15-5", "section": "§15.5", "name": "Independence Transition Framework", "text": "The independence transition framework (§15.5.a through §15.5.e) governs the period between a successful §15.4 independence referendum and formal independence. Key provisions: the Framework Agreement must be negotiated before independence takes effect; a minimum 24-month and maximum 60-month transiti"}, {"id": "s15-5-a", "section": "§15.5.a", "name": "Framework Agreement Requirement", "text": ""}, {"id": "s15-5-b", "section": "§15.5.b", "name": "Transition Period — 24 to 60 Months", "text": "Formal independence takes effect no sooner than 24 months and no later than 60 months after referendum certification. The departing territory remains part of the Republic for all constitutional purposes during the transition — Article I rights continue in force, BNF floor distributions continue as s"}, {"id": "s16-116-2", "section": "§16.1–16.2", "name": "Electoral Commission", "text": "The Electoral Commission is five members, all elected by citizens at staggered intervals . No member may have held elected office or party membership within ten years."}, {"id": "s16-2", "section": "§16.2", "name": "Electoral Commission Qualifications", "text": "Electoral Commission members must meet three independently verified requirements: at least 15 years of professional expertise in elections, technology, or public administration; no current or recent partisan affiliation; and passage of the Constitutional Logic Test. The qualifications are substantiv"}, {"id": "s16-3", "section": "§16.3", "name": "NVS Properties", "text": "Three constitutionally required properties of the National Voting System: ballot secrecy (technically impossible to link any vote to any voter), public auditability (aggregate results mathematically verifiable by anyone with NRS access), and resilience (capable of operating in degraded conditions wi"}, {"id": "s16-3-a", "section": "§16.3.a", "name": "Ballot Secrecy", "text": "No person or institution — including Electoral Commission members — may identify how any individual citizen voted. Ballot secrecy is constitutionally absolute. The NVS must make it technically impossible to link any vote to any voter, even in post-election audits."}, {"id": "s16-3-b", "section": "§16.3.b", "name": "Public Auditability", "text": "The aggregate results of every election must be mathematically verifiable by any person with access to the NRS. Election results are not simply announced — they are published in a form that allows independent mathematical verification. Any discrepancy between announced results and verifiable NRS dat"}, {"id": "s16-4-a", "section": "§16.4.a", "name": "The Citizen Voting Credential", "text": "The Citizen Voting Credential is issued and managed by the Electoral Commission. The system stores only cryptographic identifiers — not names, biometric data, or personal information — ensuring the link between a citizen and their credential cannot be used to..."}, {"id": "s16-4-b", "section": "§16.4.b", "name": "Remote Voting", "text": "the Legislature may by statute authorize authenticated remote voting through the National Voting System. No statute may permanently prohibit remote voting as a method of participation."}, {"id": "s16-5-a", "section": "§16.5.a", "name": "Campaign Funding", "text": "Campaigns for Electoral Commission seats are publicly funded in full. No private money may be spent on EC campaigns. The EC administers elections for all other offices — it cannot itself be captured by the interests that it would regulate in other campaigns."}, {"id": "s16-5-b", "section": "§16.5.b", "name": "JI Oversight", "text": "The Judicial Inspectorate audits the Electoral Commission annually. The JI is the appropriate Inspectorate for EC oversight — it audits judicial independence, and electoral integrity has similar structural properties. JI audit findings on the EC are published to the NRS and presented to both chamber"}, {"id": "s16-5-c", "section": "§16.5.c", "name": "Removal", "text": "Electoral Commission members may only be removed by for-cause process under the Track 1 standard. No-cause removal of EC members is constitutionally prohibited — the body that administers elections cannot be politically dismissible by the party that wins them."}, {"id": "s16-5-d", "section": "§16.5.d", "name": "Mid-Term Vacancy", "text": "When any Electoral Commission seat becomes vacant mid-term, a special election is held within 90 days for seats originally filled by popular vote; a joint session of the Legislature is convened within 90 days for seats originally filled by the Legislature. Replacements serve the remainder of the ori"}, {"id": "s17-2", "section": "§17.2", "name": "Seat of Government", "text": "The Republic does not have a permanent capital city with territorial sovereignty. The Seat of Government is hosted by a consenting State — the host retaining sovereignty outside the specific federal footprint. The Republic exercises functional authority, not territorial sovereignty, within the footp"}, {"id": "s17-2-a", "section": "§17.2.a", "name": "Host State Consent", "text": "The host State consents to hosting the Seat of Government by a majority vote of its legislature, recorded on the NRS. Consent is explicit, documented, and revocable. A State cannot be involuntarily assigned as the host."}, {"id": "s17-2-c", "section": "§17.2.c", "name": "Resident Rights", "text": "Citizens residing in the vicinity of the Seat of Government are full citizens of the Republic and of the host State. They vote in State and federal elections and are represented in both chambers. Residence near the federal government does not create second-class citizenship."}, {"id": "s17-3-a", "section": "§17.3.a", "name": "Registration", "text": "Every federal operational use right must be registered on the NRS with precise geographic boundaries, authorized purpose, and termination conditions. There are no unregistered federal land claims. Federal property rights are explicit, bounded, and auditable."}, {"id": "s17-3-b", "section": "§17.3.b", "name": "Termination and Reversion", "text": "When a federal function ends, the use right terminates automatically within 30 days and the land reverts to the host State with all improvements. No legislation is required; termination is the automatic outcome of functional completion."}, {"id": "s17-4", "section": "§17.4", "name": "The National Trust", "text": "The National Trust."}, {"id": "s17-4-a", "section": "§17.4.a", "name": "Trust Nature", "text": "National Trust lands are held in perpetuity for the public benefit of preservation, ecological integrity, and public access. The trust nature means the federal government manages them as a fiduciary for the public — it cannot sell or develop them even if it wishes to."}, {"id": "s17-4-d", "section": "§17.4.d", "name": "Reclassification Threshold", "text": "Removing any land from National Trust status requires a national referendum under §11.1 — the same high bar as overturning legislation. This makes Trust land reclassification one of the most difficult constitutional acts available, preventing systematic disposal of protected lands through partisan l"}, {"id": "s18-1-b", "section": "§18.1.b", "name": "Natural Persons Only", "text": "Only individual human beings who are citizens or legal residents may make financial contributions to campaigns. Corporate and organisational contributions are constitutionally prohibited."}, {"id": "s18-1-c", "section": "§18.1.c", "name": "Voter-Donor Parity", "text": "Only a citizen eligible to vote in a particular election may make financial contributions to candidates or measures in that election. The voter-donor parity rule connects electoral giving to electoral eligibility: you may give money only to elections in which you may vote."}, {"id": "s18-1-d", "section": "§18.1.d", "name": "Full Disclosure", "text": "All financial transactions connected to any election must be disclosed publicly and in real time to the Campaign Finance Registry. Real-time disclosure means contributions are visible before the election, not only in post-election reports. Citizens can see who is funding whom before they vote."}, {"id": "s18-2-a", "section": "§18.2.a", "name": "Qualification Threshold", "text": "Candidates may qualify for public funding by demonstrating sufficient popular support through verified small-dollar contributions. The qualification threshold ensures public funding flows to candidates with genuine grassroots support, not to fringe campaigns."}, {"id": "s18-3-a", "section": "§18.3.a", "name": "Separation from the Voting System", "text": "The Campaign Finance Registry is constitutionally separated from the National Voting System — different infrastructure, different administrators, different security protocols. Combining them would allow contribution history to be linked to voting behavior. The separation is a constitutional privacy "}, {"id": "s18-3-b", "section": "§18.3.b", "name": "Registry Contents", "text": "The Registry publicly records: contributor identity, amount, date, recipient, and the purpose of each expenditure. The level of detail is constitutionally mandated — partial disclosure systems that reveal totals but conceal sources do not satisfy the constitutional requirement."}, {"id": "s18-3-c", "section": "§18.3.c", "name": "Aggregate Attribution", "text": ""}, {"id": "s18-1-a", "section": "§18.1.a", "name": "Financial Contributions as Electoral Acts", "text": "Financial contributions to electoral campaigns are not constitutionally protected speech under §1.4, and are not protected as associational activity under §1.7. The regulation of electoral finance is a matter of democratic integrity explicitly reserved from both speech and associational protection. "}, {"id": "s19-9-a", "section": "§19.9.a", "name": "TAM Establishment and Scope", "text": "TAM Establishment and Scope."}, {"id": "s19-9-b", "section": "§19.9.b", "name": "TAM Amendment and Successor Bar", "text": "The establishing statute and any amendments to it require the same 2/3 majority of both chambers as the original statute. No amendment may expand the Mechanism's subject matter scope beyond the scope defined in the establishing statute."}, {"id": "s19-9-c", "section": "§19.9.c", "name": "TAM Jurisdiction and Publication Limits", "text": "The Mechanism may not exercise criminal jurisdiction — that remains with the courts. The Mechanism may not issue orders whose practical effect is equivalent to criminal punishment, including mandatory prosecution referrals with binding recommendations, civil..."}, {"id": "s19-9-d", "section": "§19.9.d", "name": "TAM Sunset and Rationale", "text": "At sunset the Mechanism dissolves; its NRS record is permanent. The Legislature may not extend the Mechanism beyond its statutory sunset without a fresh 2/3 supermajority in both chambers; extension is not a renewal and does not reset the ten-year successor bar..."}, {"id": "s19-6", "section": "§19.6", "name": "Pre-Existing Obligations", "text": "The Republic assumes the pre-existing public debt obligations of its predecessor governments on terms the transition framework specifies."}, {"id": "s19-6-a", "section": "§19.6.a", "name": "Debt Assumption", "text": "The Republic assumes all legally recognized debts of the prior government. The Republic does not inherit a clean slate — it inherits what was borrowed. Selective repudiation of prior obligations is not available as a founding act."}, {"id": "s19-6-c", "section": "§19.6.c", "name": "Social Insurance Programs", "text": "Existing social insurance programs — retirement pensions, disability benefits, health coverage — of the prior government continue uninterrupted during the Transition Window. The Republic does not create a gap in social protection as part of its founding."}, {"id": "s19-6-e", "section": "§19.6.e", "name": "Constitutional Claims Court", "text": "The immediate nullification of laws conflicting with the Individual Sovereignty Floor creates a flood of existing legal relationships that depended on now-void law. The Constitutional Claims Court provides a forum for affected parties to seek remedy without the normal backlog of established courts."}, {"id": "s19-8", "section": "§19.8", "name": "Transition Candidate Registers", "text": "The joint Inspectorate panel assembles initial Candidate Registers for all constitutionally required positions — ensuring qualified individuals are available for Day Zero appointments."}, {"id": "s19-9", "section": "§19.9", "name": "Transitional Accountability Mechanism", "text": "Where a ratifying polity's predecessor government has documented constitutional violations — systematic rights abuses, documented atrocities — the Republic may establish a Transitional Accountability Mechanism by statute. The TAM is time-limited, non-criminal (it cannot impose criminal sentences), a"}, {"id": "s20-1", "section": "§20.1", "name": "Associated Community Status", "text": "Exclusively for sovereign entities — not a form of State or Territory status, not transitional, not incorporation . Available to nations that have completed the independence process under §15.4-15.5, to independent nations outside the Republic seeking a defined relationship, or to nations recognised"}, {"id": "s20-2", "section": "§20.2", "name": "Compact Terms and Equal Sovereignty", "text": "Equal parties; neither constitutionally superior. Observing delegates attend House and Senate proceedings relevant to the compact — speaking rights, no vote, no quorum or threshold effect . The Republic may not impose its constitutional governance architecture on an Associated Community as a conditi"}, {"id": "s20-3", "section": "§20.3", "name": "Compact Conditions and Compliance", "text": "No compact may be entered or ratified with any entity whose governance practices include, authorise, or systematically permit torture, slavery, or the denial of habeas corpus to any person within its jurisdiction. The Judicial Inspectorate certifies..."}, {"id": "s20-4", "section": "§20.4", "name": "Sovereign Mobility", "text": "The Associated Community may at any time, by its own democratic or traditional governance process, elect to terminate the compact and proceed as a fully independent sovereign nation. No Republic consent is required for compact termination by the Associated..."}, {"id": "s20-5", "section": "§20.5", "name": "Reciprocal Obligations and Review", "text": ""}, {"id": "s19-3-a", "section": "§19.3.a", "name": "Phase 0 — Pre-Ratification Preparation", "text": "Phase 0 is the pre-ratification preparation period. The interim Electoral Commission is constituted, the National Voting System is certified operational, and the joint Inspectorate panel is formed — all before any ratification vote occurs. The Republic's constitutional infrastructure must exist befo"}, {"id": "s19-3-b", "section": "§19.3.b", "name": "Phase 1 — Emergency Stabilization (Days 1–90)", "text": ""}, {"id": "s19-3-c", "section": "§19.3.c", "name": "Phase 2 — Institutional Construction (Days 91–270)", "text": ""}, {"id": "s19-3-d", "section": "§19.3.d", "name": "Phase 3 — First Elections (Days 271–450)", "text": "Phase 3 (Days 271-450) is First Elections. The first National Election Day. Supreme Court justices elected through the Triad. Electoral Commission inaugural elections. Phase 3 ends when the first the Legislature is sworn in and the first executives take office — the moment at which the Republic's co"}, {"id": "s19-3-e", "section": "§19.3.e", "name": "Phase 4 — Full Constitutional Operation", "text": "Phase 4 is Full Constitutional Operation — beginning the day the first Legislature convenes and the first executives take the constitutional oath. From Phase 4, all constitutional provisions are fully operative. The 18-month Transition Window concludes at the end of Phase 4."}];